+                end = end_result.code;
+            } else if (args.len == 2) {
+                const start_result = try expressions.visitExpr(self, args[0]);
+                const end_result = try expressions.visitExpr(self, args[1]);
+                start = start_result.code;
+                end = end_result.code;
+            } else if (args.len == 3) {
+                const start_result = try expressions.visitExpr(self, args[0]);
+                const end_result = try expressions.visitExpr(self, args[1]);
+                const step_result = try expressions.visitExpr(self, args[2]);
